 1	import React, { FC } from 'react';
 2	
 3	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 4	import { Checkbox, Flex, FlexItem, FormGroup, Popover } from '@patternfly/react-core';
 5	import { HelpIcon } from '@patternfly/react-icons';
 6	
 7	type CloneStorageCheckboxProps = {
 8	  isChecked: boolean;
 9	  onChange: (checked: boolean) => void;
10	};
11	
12	const CloneStorageCheckbox: FC<CloneStorageCheckboxProps> = ({ isChecked, onChange }) => {
13	  const { t } = useKubevirtTranslation();
14	
15	  return (
16	    <FormGroup fieldId="clone-storage">
17	      <Flex alignItems={{ default: 'alignItemsCenter' }}>
18	        <FlexItem>
19	          <Checkbox
20	            id="clone-storage"
21	            isChecked={isChecked}
22	            label={t("Copy template's boot source disk")}
23	            onChange={(_, checked: boolean) => onChange(checked)}
24	          />
25	        </FlexItem>
26	        <FlexItem>
27	          <Popover
28	            bodyContent={() => (
29	              <div>
30	                {t(
31	                  'Checking this option will create a new PVC of the bootsource for the new template',
32	                )}
33	              </div>
34	            )}
35	            aria-label={'Help'}
36	          >
37	            <HelpIcon />
38	          </Popover>
39	        </FlexItem>
40	      </Flex>
41	    </FormGroup>
42	  );
43	};
44	
45	export default CloneStorageCheckbox;

